  "options": [
    {
      "text": "Devuelve una fila por cada fila coincidente, ignora las filas no coincidentes"
    },
    {
      "text": "Devuelve todas las filas de la tabla izquierda, más las filas coincidentes de la tabla derecha"
    },
    {
      "text": "Devuelve todas las filas coincidentes o no coincidentes, donde los valores NULL indican que no hay coincidencia"
    },
    {
      "text": "Devuelve todas las filas de la tabla derecha, con cualquier fila coincidente de la tabla izquierda"
    }
  ],
  "questionProse": [
    "¿Qué hace un `LEFT JOIN` en SQL?"
  ],
  "explanationProse": [
    "Un `LEFT JOIN` devuelve todas las filas de la tabla izquierda y las filas coincidentes de la tabla derecha, con NULL para las filas no coincidentes en la tabla derecha."
  ]
}
